import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;
const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

interface Checkout { cardNumber: string; cvv: string; amountCents: number }

const checkCard = (c: string): E.Either<Errs, string> =>
  /^\d{16}$/.test(c) ? E.right(c) : E.left([fe("cardNumber", "must be 16 digits")]);
const checkCvv = (c: string): E.Either<Errs, string> =>
  /^\d{3}$/.test(c) ? E.right(c) : E.left([fe("cvv", "must be 3 digits")]);
const checkAmount = (a: number): E.Either<Errs, number> =>
  a > 0 ? E.right(a) : E.left([fe("amountCents", "must be > 0")]);

export const validateCheckout = (c: Checkout): E.Either<Errs, Checkout> =>
  pipe(
    sequenceT(V)(checkCard(c.cardNumber), checkCvv(c.cvv), checkAmount(c.amountCents)),
    E.map(([cardNumber, cvv, amountCents]) => ({ cardNumber, cvv, amountCents }))
  );
```

`sequenceT` with the validation applicative runs all three checks and merges their failure lists; an invalid card AND an invalid CVV will both appear in the resulting `ReadonlyNonEmptyArray<FieldError>`.

