import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Order {
  totalCents: number;
  itemCount: number;
  shippingCountry: string;
  couponCode?: string;
}

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const minTotal = (o: Order): E.Either<Errs, Order> =>
  o.totalCents >= 500 ? E.right(o) : E.left([fe("totalCents", "minimum order is $5.00")]);
const maxItems = (o: Order): E.Either<Errs, Order> =>
  o.itemCount <= 50 ? E.right(o) : E.left([fe("itemCount", "cannot exceed 50")]);
const validCountry = (o: Order): E.Either<Errs, Order> =>
  ["US", "CA", "MX"].includes(o.shippingCountry)
    ? E.right(o)
    : E.left([fe("shippingCountry", "only US/CA/MX supported")]);

export const validateOrder = (o: Order): E.Either<Errs, Order> =>
  pipe(
    sequenceT(V)(minTotal(o), maxItems(o), validCountry(o)),
    E.map(() => o)
  );
```

All three rules run regardless of each other's outcome; a too-small total plus an unsupported country yields a two-element `ReadonlyNonEmptyArray<FieldError>` instead of the caller having to resubmit after fixing one at a time.

