```ts
// `E.chain` is fail-fast: the user fixes redisUrl, reruns, now sees the
// concurrency error, fixes that, reruns, sees retryLimit. Three round-trips
// for three errors. The validation applicative fixes this by surfacing all
// three in one pass.

import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface QueueConfig { redisUrl: string; concurrency: number; retryLimit: number }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const redis = (s: string): E.Either<Errs, string> =>
  /^redis:\/\//.test(s) ? E.right(s) : E.left([fe("redisUrl", "must start with redis://")]);
const conc = (n: number): E.Either<Errs, number> =>
  n >= 1 && n <= 256 ? E.right(n) : E.left([fe("concurrency", "1..256")]);
const retry = (n: number): E.Either<Errs, number> =>
  n >= 0 && n <= 10 ? E.right(n) : E.left([fe("retryLimit", "0..10")]);

export const validateQueueConfig = (c: QueueConfig): E.Either<Errs, QueueConfig> =>
  pipe(
    sequenceT(V)(redis(c.redisUrl), conc(c.concurrency), retry(c.retryLimit)),
    E.map(([redisUrl, concurrency, retryLimit]) => ({ redisUrl, concurrency, retryLimit }))
  );
```

Every check is independent; `sequenceT` under the validation applicative runs them all and pushes every failure into the `ReadonlyNonEmptyArray<FieldError>` that the caller can render in a single error panel.

