// `Effect.all` short-circuits on the first error, so the caller has to fix
// one field, rerun, fix the next. Wrapping every check in `Effect.either`
// turns failures into data, and `Effect.forEach(..., { discard: false })`
// runs them all so we can then collect every Left into one list.

import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface LogConfig { level: string; destination: string; format: "json" | "text" }

const level = (s: string): Effect.Effect<string, FieldError> =>
  ["trace", "debug", "info", "warn", "error"].includes(s)
    ? Effect.succeed(s)
    : Effect.fail(fe("level", "unknown level"));
const dest = (s: string): Effect.Effect<string, FieldError> =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(fe("destination", "required"));
const format = (s: string): Effect.Effect<"json" | "text", FieldError> =>
  s === "json" || s === "text" ? Effect.succeed(s) : Effect.fail(fe("format", "json|text"));

export const validateLogConfig = (
  c: LogConfig
): Effect.Effect<LogConfig, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const checks = [level(c.level), dest(c.destination), format(c.format)] as const;
    const results = yield* Effect.forEach(checks, (e) => Effect.either(e), { discard: false });
    const errs: FieldError[] = [];
    for (const r of results) if (Either.isLeft(r)) errs.push(r.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return c;
  });
```

