  s.length > 0 ? Effect.succeed(s) : Effect.fail(fe("action", "required"));
const meta = (s: string): Effect.Effect<string, FieldError> =>
  s.length <= 1024 ? Effect.succeed(s) : Effect.fail(fe("meta", "too large"));

// `Effect.flatMap` chains short-circuit. `Effect.either` + `Effect.all`
// accumulates — every failing field lands in the final error list.
export const validatePayload = (
  p: Payload
): Effect.Effect<Payload, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [u, a, m] = yield* Effect.all([
      Effect.either(userId(p.userId)),
      Effect.either(action(p.action)),
      Effect.either(meta(p.meta)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(u)) errs.push(u.left);
    if (Either.isLeft(a)) errs.push(a.left);
    if (Either.isLeft(m)) errs.push(m.left);
