```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Headers {
  "x-request-id": string | undefined;
  "content-type": string | undefined;
  authorization: string | undefined;
}

const reqId = (v: string | undefined): Effect.Effect<string, FieldError> =>
  v && /^[0-9a-f-]{8,}$/.test(v)
    ? Effect.succeed(v)
    : Effect.fail(fe("x-request-id", "missing or bad"));
const ct = (v: string | undefined): Effect.Effect<string, FieldError> =>
  v === "application/json" ? Effect.succeed(v) : Effect.fail(fe("content-type", "need application/json"));
const auth = (v: string | undefined): Effect.Effect<string, FieldError> =>
  v && v.startsWith("Bearer ") ? Effect.succeed(v) : Effect.fail(fe("authorization", "need Bearer <token>"));

export const validateHeaders = (
  h: Headers
): Effect.Effect<Headers, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [rid, c, a] = yield* Effect.all([
      Effect.either(reqId(h["x-request-id"])),
      Effect.either(ct(h["content-type"])),
      Effect.either(auth(h.authorization)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(rid)) errs.push(rid.left);
    if (Either.isLeft(c)) errs.push(c.left);
    if (Either.isLeft(a)) errs.push(a.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return h;
  });
```

Each `Effect.either` converts a per-header failure into an `Either`; `Effect.all` evaluates every one, and a missing request-id AND a wrong content-type both end up in the same `ReadonlyArray<FieldError>`.

```ts
import { Effect } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Evt { id: string; ts: number; kind: string }

const checkOne = (ev: Evt): Effect.Effect<Evt, FieldError> => {
  if (!/^evt_/.test(ev.id)) return Effect.fail(fe("id", `bad id: ${ev.id}`));
  if (!(ev.ts > 0)) return Effect.fail(fe("ts", `bad ts on ${ev.id}`));
  if (!ev.kind) return Effect.fail(fe("kind", `empty kind on ${ev.id}`));
  return Effect.succeed(ev);
};

// Returns the split: all bad events as FieldError list + all good events.
export const validateEvents = (
  events: ReadonlyArray<Evt>
): Effect.Effect<readonly [ReadonlyArray<FieldError>, ReadonlyArray<Evt>]> =>
  Effect.partition(events, checkOne);
```

`Effect.partition(items, fn)` is the canonical Effect v3 primitive for batch validation: every item is validated, every failure becomes a `FieldError`, and the result is `[errors, successes]` with no short-circuit.

