// `Effect.all` is fail-fast: the first error aborts the whole computation and
// the user only sees one bad field at a time. Wrapping each per-field check
// in `Effect.either` reifies the failure as data, so `Effect.all` runs every
// branch and we collect every `Left` into one `ReadonlyArray<FieldError>`.

import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface NameForm { firstName: string; lastName: string; email: string }

const first = (s: string): Effect.Effect<string, FieldError> =>
  s.trim().length > 0 ? Effect.succeed(s) : Effect.fail(fe("firstName", "required"));
const last = (s: string): Effect.Effect<string, FieldError> =>
  s.trim().length > 0 ? Effect.succeed(s) : Effect.fail(fe("lastName", "required"));
const email = (s: string): Effect.Effect<string, FieldError> =>
  /.+@.+\..+/.test(s) ? Effect.succeed(s) : Effect.fail(fe("email", "bad format"));

export const validateNameForm = (
  n: NameForm
): Effect.Effect<NameForm, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [f, l, e] = yield* Effect.all([
      Effect.either(first(n.firstName)),
      Effect.either(last(n.lastName)),
      Effect.either(email(n.email)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(f)) errs.push(f.left);
    if (Either.isLeft(l)) errs.push(l.left);
    if (Either.isLeft(e)) errs.push(e.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return n;
  });
```

The idiom is `Effect.either` + `Effect.all` + collect-lefts: it turns the fail-fast pipeline into an accumulating one whose error channel is a `ReadonlyArray<FieldError>` containing every broken field.

```ts
import { Effect } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Order {
  totalCents: number;
  country: string;
  itemCount: number;
  expectedRevision: number;
  actualRevision: number;
}

type Rule = (o: Order) => Effect.Effect<string, FieldError>;

const minRule: Rule = (o) =>
  o.totalCents >= 500 ? Effect.succeed("totalCents") : Effect.fail(fe("totalCents", "min $5"));
const countryRule: Rule = (o) =>
  ["US", "CA"].includes(o.country)
    ? Effect.succeed("country")
    : Effect.fail(fe("country", "US|CA only"));
const itemsRule: Rule = (o) =>
  o.itemCount > 0 && o.itemCount <= 50
    ? Effect.succeed("itemCount")
    : Effect.fail(fe("itemCount", "1..50"));
const revisionRule: Rule = (o) =>
  o.expectedRevision === o.actualRevision
    ? Effect.succeed("expectedRevision")
    : Effect.fail(fe("expectedRevision", `stale: want ${o.expectedRevision}, got ${o.actualRevision}`));

const rules: ReadonlyArray<Rule> = [minRule, countryRule, itemsRule, revisionRule];

export const validateOrder = (
  o: Order
): Effect.Effect<Order, readonly [FieldError, ...FieldError[]]> =>
  Effect.gen(function* () {
    yield* Effect.validateAll(rules, (r) => r(o));
    return o;
  });
```

`Effect.validateAll(rules, (r) => r(o))` runs every rule, and any failures accumulate into the error channel as a `NonEmptyArray<FieldError>` — adding the fourth optimistic-concurrency rule is a one-line push onto the rules list.
